	for _, g := range groups {
		g := g
		t.Run(g.domain, func(t *testing.T) {
			for _, c := range g.cases {
				req, _ := http.NewRequest(c.method, srv.URL+c.path, strings.NewReader(c.body))
				if c.body != "" {
					req.Header.Set("Content-Type", "application/json")
				}
				for k, v := range c.headers {
					req.Header.Set(k, v)
				}
				resp, err := http.DefaultClient.Do(req)
				if err != nil {
					t.Fatalf("%s %s: request error %v", c.method, c.path, err)
				}
				if resp.StatusCode != c.want {
					t.Fatalf("%s %s: status %d, want %d", c.method, c.path, resp.StatusCode, c.want)
				}
				if c.expect != "" {
					var got, exp map[string]any
					if err := json.NewDecoder(resp.Body).Decode(&got); err != nil {
						t.Fatalf("%s %s: body not JSON: %v", c.method, c.path, err)
					}
					_ = json.Unmarshal([]byte(c.expect), &exp)
					for k, v := range exp {
						gv, ok := got[k]
						if !ok {
							t.Fatalf("%s %s: body[%q] missing", c.method, c.path, k)
						}
						gj, _ := json.Marshal(gv) // canonical-JSON equality — ONE deep-equal semantic across languages
						ej, _ := json.Marshal(v)
						if string(gj) != string(ej) {
							t.Fatalf("%s %s: body[%q] = %s, want %s", c.method, c.path, k, gj, ej)
						}
					}
				}
				resp.Body.Close()
			}
		})
	}
